INSERT INTO public.leads VALUES (88, 'Asian Paints Ltd', 'paints', 'Maharashtra', 'Mumbai (Andheri East)', 'Head Procurement (Chemicals)', 'VP Supply Chain', 'https://www.asianpaints.com', 'https://www.linkedin.com/company/asian-paints', '+91 22 6235 XXXX', 'Annual Report', '{Decorative,Industrial,"Market Leader"}', 'Pitch our silane-based adhesion promoters for Apex Ultima exterior coatings and defoamers for their water-based emulsion paint lines. With $4.2B revenue and 50%+ market share, even small additive improvements translate to massive volume orders. Lead with a technical data package showing performance improvement in their specific formulation systems.', 'India''s largest paint company. Centralized buying in Mumbai HQ but plants trigger requisitions. Khandala & Kasna plants are key.', 'New', false, '2026-02-18 21:04:40.144907', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (89, 'Kansai Nerolac Paints', 'paints', 'Maharashtra', 'Mumbai (Lower Parel)', 'Technical Purchase Manager', 'Manager', 'https://www.nerolac.com', 'https://www.linkedin.com/company/kansai-nerolac-paints-ltd', '+91 22 2493 XXXX', 'Public DB', '{Automotive,Industrial,"Powder Coating"}', 'Pitch our epoxy resins and hardeners for their automotive coatings line, plus low-VOC defoamer additives for their industrial paint range. Japanese parent company standards demand consistent quality and regulatory compliance — our low-VOC systems align with their sustainability targets. Propose a technical seminar on next-generation low-VOC coating additives for their R&D team.', 'Japanese parent (Kansai Paint). Strong quality standards. Manufacturing at Lote Parshuram. Needs low-VOC compliant additives.', 'New', false, '2026-02-18 21:04:40.148514', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (90, 'Berger Paints India', 'paints', 'Maharashtra', 'Mumbai', 'Procurement Manager (Resins)', 'Procurement', 'https://www.bergerpaints.com', 'https://www.linkedin.com/company/berger-paints-india', '+91 22 6666 XXXX', 'Public Listed', '{Decorative,Industrial,Waterproofing}', 'Pitch our waterproofing additives and silicone-based water repellents for their expanding waterproofing segment, plus defoamers for their decorative paint lines across 13 plants. Their strong push into waterproofing chemicals creates a new high-growth demand channel for our silicone technology. Offer a joint product development proposal for their next-generation waterproofing range.', 'Strong push into waterproofing chemicals segment. Looking for advanced technology partners.', 'New', false, '2026-02-18 21:04:40.151843', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (91, 'Indigo Paints Ltd', 'paints', 'Rajasthan', 'Jodhpur', 'Plant Head (Chemicals)', 'Operations', 'https://www.indigopaints.com', 'https://www.linkedin.com/company/indigo-paints', '+91 291 XXX XXXX', 'Public Listed', '{Decorative,"Fast Growing","2 Plants"}', 'Pitch our defoamers for their water-based emulsion paints and epoxy resin systems for their floor coating range at both Jodhpur production units. As a fast-growing challenger brand, they are more accessible for new vendor relationships than industry giants. Lead with competitive pricing and offer a free trial batch for their Jodhpur plant to evaluate.', 'HQ moving to Jodhpur production base. Fast-growing challenger brand. More accessible than Asian Paints for new vendor relationships.', 'New', false, '2026-02-18 21:04:40.154787', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (96, 'Gujarat Colours & Coatings (GCCL)', 'paints', 'Gujarat', 'Ahmedabad', 'Factory Manager', 'Operations', '', '', '+91 79 2583 XXXX', 'Industry Dir', '{"Industrial Paints",Solvents,Automotive}', 'Pitch our specialty resins and defoamer additives for their industrial paint and automotive coating lines. With 3+ decades in industrial paints, they are a reliable regional buyer in Gujarat — easier to onboard than national brands. Offer a free trial batch and propose a quarterly supply agreement with competitive pricing.', 'Regional leader in Gujarat. Automotive finishes are their strength. Easier entry point than national brands.', 'New', false, '2026-02-18 21:04:40.171454', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (98, 'Finolex Industries Ltd', 'pvc', 'Maharashtra', 'Pune', 'Head of Sourcing', 'Sourcing', 'https://www.finolexpipes.com', 'https://www.linkedin.com/company/finolex-industries', '+91 20 2714 XXXX', 'Public Listed', '{PVC,CPVC,uPVC,Agriculture}', 'Pitch our Ca-Zn stabilizers, impact modifiers, and processing aids for their 3.2+ lakh MT PVC pipe extrusion lines. As India''s #2 pipe manufacturer with ~18% market share and strong agricultural focus, they need cost-effective lead-free stabilizer alternatives. Offer a plant-level trial with our Ca-Zn system and a cost comparison vs. their current stabilizer package.', 'Founded 1981. Pune-based manufacturing. Strong in agricultural PVC pipes. Quality-conscious procurement.', 'New', false, '2026-02-18 21:04:40.179571', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (99, 'Prince Pipes & Fittings', 'pvc', 'Maharashtra', 'Mumbai', 'Sourcing VP', 'Director', 'https://www.princepipes.com', 'https://www.linkedin.com/company/prince-pipes-and-fittings-ltd', '+91 22 6602 XXXX', 'Public Listed', '{PVC,CPVC,PPR,SWR}', 'Pitch our Ca-Zn stabilizers and PE waxes for PVC extrusion across their rapidly expanding 4.2+ lakh MT capacity at Kolhapur and 6 other locations. With ~15% annual growth, their scaling production needs reliable domestic stabilizer supply with consistent quality. Lead with a competitive volume pricing proposal and offer free trial batches at their nearest plant.', 'Founded 1987. Kolhapur plant in Maharashtra + 6 other locations. Expanding rapidly in CPVC segment.', 'New', false, '2026-02-18 21:04:40.182947', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (101, 'Jain Irrigation Systems', 'pvc', 'Maharashtra', 'Jalgaon', 'Procurement Head (Polymers)', 'Procurement', 'https://www.jains.com', 'https://www.linkedin.com/company/jain-irrigation-systems', '+91 257 225 XXXX', 'Public Listed', '{Micro-irrigation,PVC,PE,Agriculture}', 'Pitch our Ca-Zn stabilizers, UV absorbers for outdoor agricultural pipes, and processing aids for their 3+ lakh MT micro-irrigation pipe production. Outdoor irrigation pipes need superior UV stabilization to prevent field degradation — our UV absorber packages are specifically formulated for agricultural pipe applications. Offer a field performance case study and free trial batch for their Jalgaon plant.', 'Founded 1986. Jalgaon-based. Pioneer in micro-irrigation. Strong agricultural focus. Large volumes.', 'New', false, '2026-02-18 21:04:40.191347', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (104, 'Hindustan Pipes & Fittings', 'pvc', 'Rajasthan', 'Jaipur (Jhotwara)', 'Director', 'Director', 'http://www.hindustanpipe.com', '', '+91 8045 476 238', 'Company Website', '{"Rigid PVC",uPVC,SWR,"ISO Certified"}', 'Pitch our Ca-Zn stabilizers for their lead-free transition across rigid PVC, elastomeric uPVC, and column pipe lines. ISO-certified operations need documented, BIS-compliant stabilizer systems as the industry shifts away from lead-based stabilizers. Offer a complete lead-free transition support package with technical guidance and trial batches.', 'Jhotwara Extension, Jaipur. Certified manufacturer. Strong in agricultural and plumbing PVC pipe segments.', 'New', false, '2026-02-18 21:04:40.200993', 'new', 0, NULL, NULL, NULL, NULL, '[]');
