INSERT INTO public.leads VALUES (106, 'Pidilite Industries', 'construction', 'Maharashtra', 'Mumbai (Andheri East)', 'Procurement Head (Chemicals)', 'VP Procurement', 'https://www.pidilite.com', 'https://www.linkedin.com/company/pidilite-industries-limited', '+91 22 2835 XXXX', 'Public Listed', '{"Dr. Fixit",Fevicol,Waterproofing}', 'Pitch our silanes for their Dr. Fixit waterproofing range and defoamers for Fevicol adhesive manufacturing lines. As the market leader with 40-50% share, their next-gen low-VOC waterproofing systems need advanced silane chemistry for superior performance. Propose a joint R&D collaboration for their next-generation waterproofing formulations.', 'Dominant construction chemicals player. Entry barrier is high, but volume is massive. Mahad plant is key manufacturing hub.', 'New', false, '2026-02-18 21:04:40.209244', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (107, 'Sika India Pvt Ltd', 'construction', 'Maharashtra', 'Mumbai', 'Category Manager (Raw Materials)', 'Procurement', 'https://in.sika.com', 'https://www.linkedin.com/company/sika-india', '+91 22 2856 XXXX', 'MNC', '{Admixtures,Waterproofing,Flooring}', 'Pitch our defoamers for concrete admixture production and silicone-based waterproofing membrane components for their construction chemicals range. Sika''s Swiss-standard quality requirements align with our pharma-grade manufacturing processes and full traceability documentation. Offer a technical presentation on defoamer performance in high-performance concrete admixtures.', 'Focus on metro tunnels, expressways, and infrastructure. Strong quality standards from Swiss HQ.', 'New', false, '2026-02-18 21:04:40.21314', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (108, 'Fosroc Chemicals India', 'construction', 'Rajasthan', 'Keshwana', 'Plant Manager', 'Operations', 'https://www.fosroc.com', 'https://www.linkedin.com/company/fosroc', '+91 1462 XXX XXX', 'Manufacturing Plant', '{Waterproofing,Admixtures,Manufacturing}', 'Pitch our defoamers for their concrete admixture manufacturing and silicone-based water repellent components for their waterproofing product line at Keshwana plant. Proximity of supply to their Rajasthan manufacturing plant reduces logistics costs and enables just-in-time delivery. Offer a plant visit to demonstrate defoamer performance in their specific admixture formulations.', 'Rajasthan manufacturing plant for Fosroc India. Good proximity for supply of raw materials. 80+ years global experience.', 'New', false, '2026-02-18 21:04:40.217334', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (111, 'Chemax Chemicals', 'construction', 'Madhya Pradesh', 'Indore', 'Technical Head', 'Technical', 'https://chemaxchemical.com', '', '+91 731 XXX XXXX', 'Company Website', '{Waterproofing,"Tile Adhesive",Multi-state}', 'Pitch our silicone-based sealant compounds, water repellents for waterproofing, and epoxy resin systems for their flooring product range. Their multi-state coverage across Maharashtra, Gujarat, Kerala, and MP means consolidated sourcing from one supplier simplifies their procurement. Propose a supply partnership with competitive pricing and technical support across their product lines.', 'Indore-based with multi-state coverage. Construction chemicals and waterproofing specialist. Growing company.', 'New', false, '2026-02-18 21:04:40.230035', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (112, 'UPL Ltd', 'agriculture', 'Maharashtra', 'Mumbai (Sion)', 'Head of Procurement (Formulations)', 'VP Procurement', 'https://www.upl-ltd.com', 'https://www.linkedin.com/company/upl', '+91 22 2407 XXXX', 'Public Listed', '{Insecticides,Fungicides,"Global #5"}', 'Pitch our silicone-based spray adjuvants (organosilicone wetting agents) to enhance pesticide leaf coverage and reduce water usage across their insecticide and fungicide formulations. As the world''s 5th largest agrochemical company with Rs 41,390 Cr revenue, even a 1% efficiency improvement on spray performance generates massive value. Propose a field trial partnership demonstrating improved efficacy with our spray adjuvants on key crop-pesticide combinations.', 'HQ in Sion, Mumbai. Global operations in 138 countries. Massive volume buyer. Focused on sustainable agriculture solutions.', 'New', false, '2026-02-18 21:04:40.232961', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (114, 'Sharda Cropchem', 'agriculture', 'Maharashtra', 'Mumbai (Vile Parle West)', 'Sourcing Head', 'Sourcing', 'https://www.shardacropchem.com', 'https://www.linkedin.com/company/sharda-cropchem', '+91 22 2618 XXXX', 'Public Listed', '{Export,Formulations,Biocides}', 'Pitch our silicone-based spray adjuvants for their export agrochemical formulations, ensuring compliance with international regulatory requirements across target markets. As an export-heavy company, adjuvants meeting EU and US EPA standards give their products a competitive edge in global markets. Lead with our international regulatory compliance documentation and offer formulation-specific adjuvant recommendations.', 'Vile Parle West, Mumbai. Export-heavy agrochemical company. Looking for additives that comply with international regulations.', 'New', false, '2026-02-18 21:04:40.240306', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (115, 'Biostadt India Ltd', 'agriculture', 'Maharashtra', 'Mumbai', 'R&D Director', 'Technical', 'https://www.biostadtindia.com', 'https://www.linkedin.com/company/biostadt-india', '+91 22 XXXX XXXX', 'Industry Directory', '{Biological,Chemical,Pan-India}', 'Pitch our silicone-based wetting agents and sticker-spreader adjuvants to improve spray coverage in both their biological and chemical pesticide formulations. Silicone adjuvants are particularly effective with biological formulations where leaf penetration and retention are critical for efficacy. Propose a field demonstration trial comparing spray performance with and without our adjuvants on their key products.', 'Pan-India presence. Growing in biological crop protection. Silicone adjuvants complement their biological formulations well.', 'New', false, '2026-02-18 21:04:40.245665', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (118, 'Dhanuka Agritech', 'agriculture', 'Rajasthan', 'Chopanki (Alwar)', 'Plant Head', 'Operations', 'https://www.dhanuka.com', 'https://www.linkedin.com/company/dhanuka-agritech', '+91 1493 XXX XXX', 'Public Listed', '{Herbicides,Fungicides,"Forbes Listed"}', 'Pitch our silicone-based spray adjuvants and wetting agents for their herbicide and fungicide formulations at their recently expanded Chopanki plant. Their ~50% capacity expansion means increased demand for formulation additives — positioning us early secures volume as they scale up. Lead with a free trial batch timed to their expansion ramp-up and offer field efficacy data.', 'Chopanki, Rajasthan manufacturing plant. Recently expanded capacity ~50%. Growing rapidly. Good entry point for Rajasthan market.', 'New', false, '2026-02-18 21:04:40.261142', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (119, 'Gharda Chemicals', 'agriculture', 'Gujarat', 'Bharuch', 'Purchase Manager', 'Procurement', 'https://www.gharda.com', 'https://www.linkedin.com/company/gharda-chemicals', '+91 2642 XXX XXX', 'Industry Directory', '{Agrochemicals,"4 Plants","Since 1967"}', 'Pitch our spray adjuvants to enhance crop protection formulation efficacy and antifoams for production across their 4 manufacturing units in Bharuch. With 55+ years in agrochemicals, they value proven, reliable suppliers — our consistent supply track record and technical support are key differentiators. Offer a multi-plant supply proposal with competitive pricing for annual contracts.', 'Bharuch, Gujarat. 4 manufacturing units. Long-established agrochemical manufacturer. Consistent quality buyer.', 'New', false, '2026-02-18 21:04:40.266164', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (121, 'Murli Industries Limited', 'paper_pulp', 'Maharashtra', 'Nagpur', 'Purchase Manager', 'Procurement', '', '', '+91 712 XXX XXXX', 'Industry Directory', '{"Duplex Board","1000+ Employees",Nagpur}', 'Pitch our Simethicone-based antifoams for foam control in their grey back duplex board pulping, washing, and forming stages. With 1000+ employees and large-scale production, even a small efficiency gain in foam management translates to significant cost savings. Our silicone antifoams offer superior persistence compared to mineral oil defoamers, reducing dosage frequency. Lead with a free plant trial to demonstrate reduced chemical consumption and improved drainage.', 'Nagpur-based. One of Maharashtra''s larger paper mills. Grey back duplex board production. Volume buyer of process chemicals.', 'New', false, '2026-02-18 21:04:40.2726', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (122, 'Ganga Papers India Ltd', 'paper_pulp', 'Maharashtra', 'Pune (Maval)', 'Factory Manager', 'Operations', '', '', '+91 2114 XXX XXX', 'Industry Directory', '{"Paper Manufacturing","Pune Region"}', 'Pitch our silicone-based defoamers for wet-end paper manufacturing — controlling foam during stock preparation, forming, and pressing stages. Their Pune-region location means fast delivery and responsive technical support from Fabrevol''s nearby operations. Our antifoams reduce sheet defects caused by entrained air and improve drainage rates. Offer a free on-site trial with dosage optimization to demonstrate measurable production improvements.', 'Village Bebedobal, Maval, Pune. Paper manufacturing. Good proximity for regular supply of process chemicals.', 'New', false, '2026-02-18 21:04:40.275619', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (124, 'Tirthak Paper Mill Pvt Ltd', 'paper_pulp', 'Gujarat', 'Morbi', 'Director', 'Director', '', '', '+91 2822 XXX XXX', 'Industry Directory', '{"Paper Mill","Morbi Hub","Since 2006"}', 'Pitch our silicone-based antifoams and defoamers for their paper production lines to reduce foam-related downtime and improve machine speed. As part of the Tirthak Multi Papers group with growing capacity since 2006, they need a reliable antifoam supplier who can scale with their expansion. Our products offer longer knockdown time than conventional defoamers, reducing re-dosing costs. Lead with a competitive pricing proposal and free trial samples.', 'Morbi, Gujarat. Part of Morbi paper hub. Established paper manufacturer with growing capacity.', 'New', false, '2026-02-18 21:04:40.286016', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (126, 'Rama Newsprint & Papers Ltd', 'paper_pulp', 'Gujarat', 'Surat (Barbodhan)', 'Plant Head', 'Operations', '', '', '+91 261 XXX XXXX', 'Industry Directory', '{Newsprint,Surat,"Large Mill"}', 'Pitch our silicone antifoams specifically formulated for de-inking and newsprint recycling processes where foam control is critical for fiber recovery. Newsprint manufacturing from recycled fiber generates persistent foam during de-inking, screening, and cleaning — our antifoams are effective at low dosages without causing spots or fisheyes on the finished sheet. Reliable local supply from our Gujarat operations ensures uninterrupted production. Offer a free de-inking process trial with before-and-after quality assessment.', 'Barbodhan, Olpad, Surat. Newsprint manufacturer. Large-scale operation requiring regular supply of paper chemicals.', 'New', false, '2026-02-18 21:04:40.293414', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (128, 'Jabali Papers Ltd', 'paper_pulp', 'Madhya Pradesh', 'Jabalpur', 'Factory Manager', 'Operations', '', '', '+91 761 XXX XXXX', 'Industry Directory', '{"Kraft Paper","Advanced Machinery","12 BF Range"}', 'Pitch our premium silicone antifoams for their advanced kraft paper production lines, targeting pulp washing and brown stock washing stages. Their investment in latest machinery indicates a quality-focused operation that would benefit from high-performance antifoams over commodity defoamers. Our antifoams are compatible with their 12 BF range production and won''t cause depositing issues on modern equipment. Lead with a technical presentation and free trial batch matched to their specific kraft grade.', 'Jabalpur, MP. Advanced kraft paper manufacturer. Latest machinery suggests quality-conscious operation. Good target for premium antifoams.', 'New', false, '2026-02-18 21:04:40.299667', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (130, 'Thermax Ltd', 'water_treatment', 'Maharashtra', 'Pune', 'Procurement Manager (Chemicals)', 'Procurement', 'https://www.thermaxglobal.com', 'https://www.linkedin.com/company/thermax', '+91 20 6630 XXXX', 'Public Listed', '{ETPs,STPs,"ZLD Systems","Boiler Chemicals"}', 'Pitch our silicone antifoams for their boiler water treatment formulations, cooling water chemicals, and ETP/STP/ZLD system applications. Thermax''s multi-project operations across India require bulk antifoam supply with consistent quality batch-to-batch — our manufacturing scale ensures that reliability. Our antifoams withstand the high-temperature, high-TDS conditions common in ZLD systems where conventional defoamers fail. Offer a technical collaboration meeting to customize antifoam grades for their specific ETP and boiler chemical formulations.', 'Pune HQ. Founded 1980. Boiler/cooling water chemicals plus ETP/STP solutions. Large-scale procurement for multiple projects.', 'New', false, '2026-02-18 21:04:40.306775', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (131, 'Chembond Chemicals Ltd', 'water_treatment', 'Maharashtra', 'Mumbai', 'Technical Sales Head', 'Technical', 'https://www.chembondindia.com', 'https://www.linkedin.com/company/chembond-chemicals', '+91 22 2541 XXXX', 'BSE/NSE Listed', '{"Specialty Chemicals","Water Tech","Since 1974"}', 'Pitch our antifoam concentrates for their water treatment chemical formulations and silicone-based water repellents for their construction chemicals division. As a BSE/NSE-listed company since 1974, they have established procurement processes — but our competitive pricing on domestic antifoam supply vs. imports creates a compelling cost advantage. Offer a dual-product sample kit covering both water treatment antifoams and construction water repellents to maximize the relationship.', 'Mumbai HQ. Specialty chemicals for water technologies and construction chemicals. Listed company. Established procurement processes.', 'New', false, '2026-02-18 21:04:40.310482', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (132, 'Gujarat Alkalies and Chemicals (GACL)', 'water_treatment', 'Gujarat', 'Vadodara & Dahej', 'GM Procurement', 'GM', 'https://www.gacl.com', 'https://www.linkedin.com/company/gacl', '+91 265 239 XXXX', 'Public Listed', '{"Caustic Soda",PAC,Chloromethanes,Export}', 'Pitch our silicone antifoams for foam control in their chlor-alkali electrolysis, hydrogen peroxide production, and PAC manufacturing processes. Their dual manufacturing complexes in Vadodara and Dahej serving 25+ export countries need process chemicals meeting international quality standards. Our antifoams are thermally stable and chemically resistant to the caustic conditions in their brine processing. Propose a multi-plant supply agreement covering both Vadodara and Dahej facilities.', 'Two major manufacturing complexes in Vadodara & Dahej. Exports to 25+ countries. Large chemical operation with multiple antifoam applications.', 'New', false, '2026-02-18 21:04:40.316376', 'new', 0, NULL, NULL, NULL, NULL, '[]');
