INSERT INTO public.leads VALUES (136, 'Kangaroo Leather Pvt Ltd', 'leather', 'Maharashtra', 'Bhiwandi (Thane)', 'Production Head', 'Operations', 'https://www.kangarooleather.in', '', '+91 2522 XXX XXX', 'Company Website', '{"Leather Belts","Leather Goods",Export}', 'Pitch our silicone-based water repellents and leather finishing sprays for their formal and casual leather belt production lines. Export-oriented leather goods need durable water resistance and a premium hand-feel — our silicone finishes deliver both without affecting dye adhesion. Domestic supply ensures shorter lead times vs. imported finishing chemicals, helping them meet tight export deadlines. Lead with free application trials on their current belt leather grades.', 'Jai Jalaram Complex, Bhiwandi. Leather goods manufacturer. Export-oriented. Uses finishing chemicals in production.', 'New', false, '2026-02-18 21:04:40.332374', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (138, 'L.V. Associates', 'leather', 'Rajasthan', 'Udaipur (Girwa)', 'Proprietor', 'Owner', '', '', '+91 294 XXX XXXX', 'Industry Directory', '{"Finished Leather",Udaipur}', 'Pitch our silicone-based leather softeners and water-repellent finishing agents for their finished leather processing in Udaipur. As a regional manufacturer, they likely source finishing chemicals from distant suppliers — our responsive supply chain offers faster delivery and technical support for their Rajasthan operations. Our silicone softeners impart a luxurious hand-feel that commands premium pricing for their finished leather. Offer a free sample kit with application guidelines tailored to their leather grades.', '21, Rajshree Colony, Girwa, Udaipur. Finished leather processor. Regional target for Rajasthan market entry.', 'New', false, '2026-02-18 21:04:40.339426', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (142, 'Megacab Wires & Cables', 'wire_cable', 'Gujarat', 'Rajkot', 'Director', 'Director', 'https://megacabwires.com', '', '+91 281 XXX XXXX', 'Company Website', '{"PVC Cables",FRLS,"ISO Certified"}', 'Pitch our Ca-Zn stabilizers for their lead-free PVC cable compounds and specialty FRLS (Fire Retardant Low Smoke) cable insulation. FRLS cables require specific stabilizer-flame retardant synergy — our Ca-Zn systems are formulated for compatibility with alumina trihydrate and other FRLS additives. Their ISO 9001:2015 certification means they value documented quality, which our technical data sheets fully support. Offer free compounding trials for their FRLS and submersible cable grades.', 'Rajkot, Gujarat. ISO certified manufacturer. FRLS cables need specific stabilizer systems. Good target for specialty PVC additives.', 'New', false, '2026-02-18 21:04:40.353934', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (143, 'Torrent Cables Limited', 'wire_cable', 'Gujarat', 'Ahmedabad', 'Purchase Manager', 'Procurement', '', '', '+91 79 2740 XXXX', 'Corporate Group', '{EHV,HT-XLPE,"Power Cables"}', 'Pitch our Ca-Zn stabilizers and processing aids for their LT-PVC power cable insulation compounding. While their EHV and HT-XLPE lines use cross-linked PE, their LT-PVC cable range is a direct application for our stabilizer systems. As part of the Torrent Group, they have established procurement standards — our consistent quality and domestic supply reliability meet corporate group requirements. Propose a vendor qualification meeting with technical data sheets and free compounding trial samples.', 'Ahmedabad. Part of Torrent Group (inc. 1991). Manufactures high-voltage to low-voltage power cables. Established procurement.', 'New', false, '2026-02-18 21:04:40.356679', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (146, 'Tirubala Footwear', 'footwear', 'Maharashtra', 'Mumbai Central', 'Procurement Head', 'Procurement', '', '', '+91 22 2309 XXXX', 'Industry Directory', '{"ISO 9001","12000 Pairs/Day",Export}', 'Pitch our silicone-based mould release agents for their 12,000+ pairs/day production across 4 factories serving Mango, Zara, and Topshop. High-volume moulding operations need release agents that extend mould life and reduce cleaning downtime — our silicone release agents deliver 30%+ more releases per application vs. conventional waxes. Their ISO 9001 certification and global brand partnerships demand documented, consistent-quality chemicals. Offer a free production-line trial with mould-life tracking data.', 'C9, Dawood Baug, Mumbai Central. 4 factories. Export-oriented, works with global fashion brands. Volume buyer of footwear chemicals.', 'New', false, '2026-02-18 21:04:40.377652', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (150, 'Tiny Chempro', 'food_processing', 'Maharashtra', 'Vasai (Palghar)', 'Sales Manager', 'Sales', '', '', '+91 250 XXX XXXX', 'Industry Directory', '{"Food Antifoam","Sugar Mills",Distilleries}', 'Pitch our food-grade silicone antifoam concentrates as OEM base material for their Tinyfoam GL 364 (potato processing) and GL 6010 (sugar/distillery) products. As an antifoam formulator, they need reliable silicone antifoam fluid supply with consistent quality and competitive pricing to protect their margins. Our domestic production offers significant landed-cost advantage over imported silicone fluid grades. Propose a bulk supply agreement with volume pricing and consistent COA documentation.', 'Vasai, Palghar. Antifoam manufacturer serving food processing industry. Could be both competitor and potential buyer of Resil silicone antifoam base.', 'New', false, '2026-02-18 21:04:40.391046', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (151, 'RX Chemicals', 'food_processing', 'Maharashtra', 'Mumbai / Pune / Nashik', 'Director', 'Director', 'https://rxchemicals.com', '', '+91 22 XXXX XXXX', 'Company Website', '{Antifoam,"25+ Cities",Multi-Industry}', 'Pitch our silicone antifoam concentrates as base raw material for their RXSOL antifoam formulation business across 25+ cities. Their multi-industry distribution network covering food, paper, and textile industries makes them an ideal channel partner for our antifoam base products. Consistent quality from our production ensures their downstream customers get reliable performance. Propose a distributor-grade bulk supply agreement with volume discounts and co-marketing support.', 'Multi-city presence. Large-scale antifoam distributor. Could be a channel partner for Resil antifoam products across food, paper, and textile industries.', 'New', false, '2026-02-18 21:04:40.395525', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (152, 'World Chem Industries', 'food_processing', 'Gujarat', 'Ankleshwar (Bharuch)', 'Director', 'Director', '', '', '+91 2646 XXX XXX', 'Industry Directory', '{"Food-grade Antifoam","Rs 10-25 Cr",GIDC}', 'Pitch our food-grade silicone antifoam base fluid as raw material for their WCI-SIDI food-grade antifoam formulations at GIDC Panoli. With Rs 10-25 Cr turnover, they consume significant volumes of silicone antifoam fluid monthly — our competitive domestic pricing directly improves their formulation margins. Proximity to our Gujarat supply chain ensures reliable, just-in-time delivery. Lead with a competitive pricing proposal with a free quality evaluation batch.', 'GIDC Panoli, Ankleshwar. Specialized in food-grade antifoam. Good target for Resil silicone antifoam base material supply.', 'New', false, '2026-02-18 21:04:40.398906', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (153, 'OM Tex Chem Pvt Ltd', 'food_processing', 'Maharashtra', 'Panvel (Raigad)', 'Technical Head', 'Technical', 'https://www.omtexchem.com', '', '+91 22 2745 XXXX', 'Company Website', '{"SILAF Series","Silicone Antifoams","Food Grade"}', 'Pitch our silicone antifoam fluid as the primary base material for their SILAF series silicone antifoam product range at Kamothe Industrial Estate. As a silicone antifoam manufacturer, they are a direct buyer of bulk silicone fluid — consistent viscosity and purity of our base fluid directly affects their end-product quality. Our domestic production eliminates import lead times and forex risk for their raw material procurement. Lead with a quality comparison batch and competitive bulk pricing proposal.', 'Plot 243/244, Kamothe Industrial Estate. Silicone antifoam manufacturer. Uses silicone fluid as base raw material - direct Resil opportunity.', 'New', false, '2026-02-18 21:04:40.402161', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (154, 'Cilantro Chemicals Pvt Ltd', 'food_processing', 'Maharashtra', 'Pune', 'Director', 'Director', '', '', '+91 20 XXXX XXXX', 'Industry Directory', '{Defoamers,"Food Processing",Multi-Industry}', 'Pitch our silicone antifoam concentrates as base raw material for their multi-industry defoamer formulations covering food processing, textile, wastewater, and sugar industries. Their diverse customer base across multiple sectors means they need a versatile silicone antifoam fluid that performs across different pH, temperature, and process conditions. Our product range covers all their formulation needs from a single source, simplifying their procurement. Offer a product portfolio presentation with free samples across their key application areas.', 'Pune-based. Supplies defoamers to food processing, textile, wastewater, and sugar industries. Multi-industry opportunity.', 'New', false, '2026-02-18 21:04:40.405726', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (159, 'Meril Life Sciences', 'medical_devices', 'Gujarat', 'Vapi', 'VP Procurement', 'VP Procurement', 'https://www.merillife.com', 'https://www.linkedin.com/company/meril-life-sciences', '+91 260 XXX XXXX', 'Company Website', '{Cardiovascular,Orthopedics,Diagnostics}', 'Pitch our medical-grade Dimethicone for catheter and guidewire lubrication coatings and silicone components for their cardiovascular and orthopedic device lines. As a rapidly growing Indian medical device company competing with global MNCs, they need medical-grade silicones with full biocompatibility documentation at competitive domestic pricing. Our silicones meet USP/ISO 10993 standards required for device contact applications. Propose a technical meeting at their Vapi facility with biocompatibility data and free evaluation samples.', 'Near Bilakhia Stadium, Vapi. Also Mumbai office at Andheri East. Rapidly growing Indian medical device company. Quality-conscious procurement.', 'New', false, '2026-02-18 21:04:40.422551', 'new', 0, NULL, NULL, NULL, NULL, '[]');
