INSERT INTO public.leads VALUES (162, 'RH Healthcare', 'medical_devices', 'Gujarat', 'Gujarat', 'Procurement Head', 'Procurement', 'https://rhhealthcareindia.com', '', '+91 XXXX XXX XXX', 'BIS Approved', '{"Examination Gloves","Sanitary Pads","BIS Approved"}', 'Pitch our silicone lubricants for their BIS-approved examination glove manufacturing and silicone release agents for sanitary pad and diaper production lines. BIS approval requires documented raw material quality — our medical-grade silicones with full certification support their compliance requirements. Serving both glove and hygiene product lines, they benefit from single-supplier procurement for silicone-based process chemicals. Offer a free trial across their glove and hygiene product lines with complete BIS-compatible documentation.', 'Gujarat-based. BIS approved medical products manufacturer. Gloves are key product requiring silicone lubricants.', 'New', false, '2026-02-18 21:04:40.433383', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (164, 'Amigo Surgi-care Pvt Ltd', 'medical_devices', 'Gujarat', 'Gandhinagar (Rakanpur)', 'Director', 'Director', '', '', '+91 2717 XXX XXX', 'Industry Directory', '{"Surgical Gloves","IV Cannulas","Surgical Disposables"}', 'Pitch our medical-grade silicones for surgical glove lubrication, IV cannula component coating, and silicone-based wound dressing treatments. Their diversified surgical disposable range uses silicone across multiple product lines — from glove donning agents to IV device coatings. Our domestic supply with full biocompatibility documentation reduces their dependency on imported medical-grade silicones. Offer a comprehensive product evaluation kit covering their glove, IV, and dressing applications with technical application support.', 'Plot 780, Sola-Santej Road, Rakanpur, Gandhinagar. Diversified surgical disposable manufacturer. Multiple silicone applications.', 'New', false, '2026-02-18 21:04:40.440678', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (167, 'Apcotex Industries Ltd', 'construction', 'Maharashtra', 'Mumbai (Taloja)', 'VP Business Development', 'Business Development', 'https://www.apcotex.com', 'https://www.linkedin.com/company/apcotex-industries', '+91 22 4080 XXXX', 'Public Listed', '{"Polymer Emulsions","SB Latex",Waterproofing}', 'Pitch our silicone-based water repellents and antifoams for their specialty acrylic polymer emulsion and SB latex manufacturing for construction waterproofing applications. Their BSE-listed, technology-driven operation values technical selling — our antifoams control foam during emulsion polymerization, improving batch consistency. Silicone water repellents can be offered as complementary additives for their waterproofing product formulations. Propose a joint technical development project combining our silicone additives with their polymer systems.', 'Taloja plant. Specialty flexible waterproofing for cement applications. BSE listed. Technical selling approach preferred.', 'New', false, '2026-02-18 21:04:40.449265', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (169, 'Apcotex Industries (Latex Div)', 'rubber_latex', 'Maharashtra', 'Mumbai (Taloja)', 'Head of R&D (Latex)', 'Technical', 'https://www.apcotex.com', 'https://www.linkedin.com/company/apcotex-industries', '+91 22 4080 XXXX', 'Public Listed', '{"Synthetic Latex","NBR Latex","SBR Latex"}', 'Pitch our silicone-based antifoams for foam control during their NBR, SBR, and specialty latex emulsion polymerization processes. Latex manufacturing generates significant foam during agitation and stripping — our antifoams provide effective knockdown without affecting latex stability or particle size distribution. As a BSE-listed producer, they value documented quality and consistent supply. Propose a process trial at their Taloja plant with dosage optimization to demonstrate reduced foam-related batch time.', 'Taloja plant. Produces NBR, SBR, and specialty latexes. BSE listed. Process chemicals buyer for latex manufacturing.', 'New', false, '2026-02-18 21:04:40.455215', 'new', 0, NULL, NULL, NULL, NULL, '[]');
