INSERT INTO public.leads VALUES (182, 'Allengers Medical Systems', 'medical_devices', 'Telangana', 'Hyderabad', 'Procurement Manager', 'Procurement', '', '', '+91 40 XXXX XXXX', 'Company Website', '{"Diagnostic Imaging",X-ray,Ultrasound}', 'Pitch our medical-grade silicones for gaskets, seals, and electrical insulation components in their X-ray, ultrasound, and MRI diagnostic imaging equipment. Medical imaging devices require silicones with exceptional dielectric properties and long-term thermal stability for safe, reliable operation. Our medical-grade silicone compounds meet IEC and ISO standards required for equipment component certifications. Propose a technical evaluation meeting with free silicone compound samples matched to their specific equipment sealing and insulation requirements.', 'Amrutha Hills, Punjagutta, Hyderabad. Medical equipment manufacturer. Uses silicone in equipment components and assemblies.', 'New', false, '2026-02-18 21:04:40.495894', 'new', 0, NULL, NULL, NULL, NULL, '[]');
