INSERT INTO public.leads VALUES (179, 'D S Enterprises', 'footwear', 'Maharashtra', 'Pune (Jejuri)', 'Proprietor', 'Owner', '', '', '+91 2115 XXX XXX', 'Industry Directory', '{"PVC Soles",Rexine,"Nagra Shoes"}', 'Pitch our Ca-Zn stabilizers and plasticizer systems for their PVC sole compound manufacturing used in Rexine Nagra shoes. Lead-free Ca-Zn stabilizers improve the weathering resistance and flexibility retention of PVC soles, reducing customer complaints about cracking. Our competitive domestic pricing directly improves their PVC compound cost per pair. Offer free compounding trial samples with a side-by-side comparison against their current stabilizer system.', 'Jejuri, Pune. PVC sole footwear manufacturer. Uses PVC compounds directly. our stabilizer opportunity.', 'New', false, '2026-02-18 21:04:40.485317', 'new', 0, NULL, NULL, NULL, NULL, '[]');
