INSERT INTO public.leads VALUES (157, 'Henkel (Loctite)', 'adhesives_sealants', 'Maharashtra', 'Kurkumbh (Pune District)', 'Plant Procurement Head', 'Procurement', 'https://www.henkel.in', 'https://www.linkedin.com/company/henkel', '+91 2111 XXX XXX', 'MNC', '{Loctite,"Industry 4.0","LEED Gold"}', 'Pitch our epoxy resins and specialty chemical intermediates for their Loctite adhesive and sealant manufacturing at their new Industry 4.0 LEED Gold facility. Their plant expansion signals growing production volumes requiring increased raw material supply — engaging during ramp-up phase positions us before procurement decisions are locked. Our epoxy grades meet the stringent quality specifications demanded by Henkel''s global MNC standards. Propose a formal vendor qualification process with comprehensive technical documentation and free resin samples.', 'Kurkumbh, Pune District. MNC with high quality standards. New Industry 4.0 plant suggests growing volumes. Difficult entry but huge volume potential.', 'New', false, '2026-02-18 21:04:40.416644', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (102, 'Raina Industries Ltd', 'pvc', 'Rajasthan', 'Dholpur', 'Plant Manager', 'Operations', 'https://www.rainaindustries.com', '', '+91 5642 XXX XXX', 'Company Website', '{"PVC Pipes",HDPE,"Water Tanks"}', 'Pitch our Ca-Zn stabilizers and PE waxes for their PVC pipe extrusion lines and HDPE processing at their Dholpur RIICO facility. As a regional leader in Rajasthan with 20+ years experience, they benefit from a reliable nearby supplier reducing lead times and logistics costs. Lead with a competitive landed-cost comparison and offer free trial samples.', 'Dholpur, RIICO Industrial Area. Manufactures PVC pipes, HDPE pipes, multi-layer water storage tanks. Regional leader in Rajasthan.', 'New', false, '2026-02-18 21:04:40.193984', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (103, 'Tijaria Poly Pipes Ltd', 'pvc', 'Rajasthan', 'Jaipur (Sitapura RIICO)', 'Purchase Manager', 'Procurement', '', '', '+91 9314 669 000', 'Industry Directory', '{PVC,HDPE,UPVC,"DWC Pipes"}', 'Pitch our Ca-Zn stabilizers and impact modifiers for their diversified PVC, HDPE, UPVC, and DWC pipe extrusion lines in Sitapura RIICO. Their diversified pipe portfolio means multiple stabilizer and additive requirements from a single supplier — simplifying their procurement. Offer a consolidated product portfolio presentation with free samples for each pipe type.', 'Sitapura RIICO, Jaipur. 4.5/5 rating. Diversified pipe manufacturer. Good target for stabilizer and processing aid sales.', 'New', false, '2026-02-18 21:04:40.197633', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (110, 'Siddhi Vinayak Construction Chemical', 'construction', 'Madhya Pradesh', 'Satna', 'Managing Director', 'Director', 'https://www.svccpl.com', '', '+91 7672 XXX XXX', 'Company Website', '{Waterproofing,"Tile Adhesive",Regional}', 'Pitch our silicone-based water repellents for their post-construction waterproofing range and epoxy systems for their tile adhesive formulations. As a regional manufacturer in Satna, they benefit from a reliable domestic supplier with shorter lead times and competitive pricing. Lead with free samples and a technical comparison vs. their current raw material suppliers.', 'Satna Industrial Area, MP. Regional construction chemicals manufacturer. Accessible for new vendor relationships.', 'New', false, '2026-02-18 21:04:40.22585', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (139, 'Polycab India Limited', 'wire_cable', 'Gujarat', 'Halol / Daman / Kutch', 'VP Procurement (Compounds)', 'VP Procurement', 'https://www.polycab.com', 'https://www.linkedin.com/company/polycab', '+91 260 XXX XXXX', 'Public Listed', '{"PVC Cables","Market Leader","10 Plants"}', 'Pitch our Ca-Zn stabilizers for lead-free PVC cable insulation compounds across their 10 manufacturing units in Halol, Daman, and Kutch. As India''s largest wire manufacturer with Rs 8,186 Cr turnover, even a small share of their stabilizer consumption represents massive volume. Our Ca-Zn systems meet EU RoHS and REACH compliance, critical for their growing export business. Propose a multi-plant supply agreement with competitive volume pricing and free processing trials.', 'Turnover Rs 8,186 Cr. Plants in Halol, Daman, Kutch. Market leader in PVC insulated wires. Massive volume buyer of PVC compounds and stabilizers.', 'New', false, '2026-02-18 21:04:40.3426', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (144, 'Prime Cable Industries Pvt Ltd', 'wire_cable', 'Rajasthan', 'Bhiwadi (Alwar)', 'Plant Head', 'Operations', 'https://www.primecabindia.com', '', '+91 1493 XXX XXX', 'Company Website', '{"Control Cables","Power Cables","ISO Certified"}', 'Pitch our Ca-Zn stabilizers and PE wax processing aids for PVC cable extrusion at their Bhiwadi facility. Their ISO 14001 environmental certification signals a commitment to lead-free manufacturing — our Ca-Zn stabilizers are the ideal replacement for legacy lead-based systems. PE waxes improve their extrusion surface finish and throughput, reducing scrap rates. Offer a free extrusion trial with side-by-side comparison against their current stabilizer system.', 'Bhiwadi, Alwar, Rajasthan. Certified cable manufacturer. Environmental certifications suggest interest in lead-free (Ca-Zn) stabilizer systems.', 'New', false, '2026-02-18 21:04:40.361782', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (145, 'Anchor (Panasonic)', 'wire_cable', 'Rajasthan', 'Bhiwadi (Alwar)', 'Sourcing Manager', 'Sourcing', 'https://www.panasonic.com/in', 'https://www.linkedin.com/company/panasonic', '+91 1493 XXX XXX', 'MNC', '{"PVC Cables",Switches,Panasonic}', 'Pitch our Ca-Zn stabilizers and PVC compound additives for their cable and switch manufacturing at Bhiwadi. Panasonic''s Japanese parent company mandates strict quality and environmental standards — our lead-free Ca-Zn systems with full RoHS documentation align perfectly with their global compliance requirements. Consistent batch quality and reliable domestic supply reduce their dependency on imported additives. Propose a formal vendor qualification process with comprehensive technical data and free compound testing.', 'Unit 1 & 2, Bhiwadi, Alwar. Panasonic-backed manufacturing. Turnover Rs 500 Cr approx. Japanese quality standards for raw materials.', 'New', false, '2026-02-18 21:04:40.365474', 'new', 0, NULL, NULL, NULL, NULL, '[]');
