INSERT INTO public.leads VALUES (166, 'Astral Ltd (Hyderabad Plant)', 'pvc', 'Telangana', 'Hyderabad', 'Plant Manager', 'Operations', 'https://www.astralpipes.com', 'https://www.linkedin.com/company/astral-pipes', '+91 40 XXXX XXXX', 'Expansion Plans', '{CPVC,"70000 MTPA",Expansion}', 'Pitch our Ca-Zn stabilizers and processing aids for their planned 70,000 MTPA CPVC capacity expansion in Hyderabad by FY2026. Engaging before new plant procurement decisions are finalized positions us as a preferred stabilizer supplier from day one of operations. Our Ca-Zn systems are specifically formulated for CPVC processing temperatures and provide superior heat stability. Propose a technical meeting with their expansion project team to align stabilizer specifications with their new plant design.', 'Hyderabad expansion planned. 70,000 MTPA new capacity. Early engagement opportunity before new plant procurement decisions are finalized.', 'New', false, '2026-02-18 21:04:40.446485', 'new', 0, NULL, NULL, NULL, NULL, '[]');
