INSERT INTO public.leads VALUES (116, 'PI Industries Ltd', 'agriculture', 'Gujarat', 'Bharuch (3 Plants)', 'VP Supply Chain', 'VP Supply Chain', 'https://www.piindustries.com', 'https://www.linkedin.com/company/pi-industries', '+91 2642 XXX XXX', 'Public Listed', '{"Custom Synthesis",Agri-Sciences,R&D}', 'Pitch our spray adjuvants for their agrochemical formulations and antifoams for manufacturing at their 3 Gujarat plants. Their strong R&D capability at the Udaipur center makes them receptive to technical data on adjuvant-formulation compatibility studies. Propose a collaborative R&D evaluation at their Udaipur center with customized adjuvant samples for their specific formulations.', 'Multiple plants in Gujarat. Strong custom synthesis business. Quality-conscious with strong R&D. Udaipur R&D center.', 'New', false, '2026-02-18 21:04:40.252216', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (117, 'Meghmani Organics Ltd', 'agriculture', 'Gujarat', 'Ahmedabad', 'Procurement Head (Additives)', 'Procurement', 'https://www.meghmani.com', 'https://www.linkedin.com/company/meghmani-organics', '+91 79 2656 XXXX', 'Public Listed', '{Insecticides,Pigments,"Rs 2195 Cr"}', 'Pitch our silicone spray adjuvants for their insecticide formulations and antifoam agents for their manufacturing processes at multiple Gujarat plants. With Rs 2,195 Cr revenue and diversified chemical manufacturing, they can evaluate both agrochemical adjuvants and industrial antifoams from a single supplier. Offer a dual-product trial covering spray adjuvants for their formulations and process antifoams for manufacturing.', 'Ahmedabad-based. Also makes pigments. Multiple manufacturing units in Gujarat. Diversified chemical company.', 'New', false, '2026-02-18 21:04:40.256696', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (120, 'Bharat Rasayan Ltd', 'agriculture', 'Gujarat', 'Bharuch (Dahej)', 'Procurement Manager', 'Procurement', 'https://www.bharatrasayan.com', 'https://www.linkedin.com/company/bharat-rasayan', '+91 2642 XXX XXX', 'Public Listed', '{Pesticides,Fungicides,"Dahej Plant"}', 'Pitch our silicone-based spray adjuvants for their pesticide and fungicide formulations and antifoams for their Dahej SEZ manufacturing operations. Dahej''s proximity to our supply chain enables cost-effective just-in-time delivery, reducing their inventory holding costs. Lead with a logistics cost-saving proposal and offer free adjuvant samples for formulation compatibility testing.', 'Dahej SEZ, Bharuch. Major agrochemical manufacturer. Pesticides, fungicides, herbicides, and acaricides.', 'New', false, '2026-02-18 21:04:40.269289', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (123, 'Bell Multikraft Pvt Ltd (BMK)', 'paper_pulp', 'Gujarat', 'Morbi (Jambudiya)', 'Procurement Head', 'Procurement', '', '', '+91 2822 XXX XXX', 'Industry Directory', '{"Kraft Paper","350+ Employees","65000 sqm"}', 'Pitch our silicone antifoams for their kraft paper pulping and black liquor processing at their 65,000 sqm facility. Kraft manufacturing generates heavy foam during cooking and washing — our antifoams maintain effectiveness at the high temperatures and alkaline pH typical of kraft processes. Consistent supply from our Gujarat operations ensures zero production downtime. Propose a free dosage trial targeting their highest-foam production line.', 'Jambudiya, Morbi. One of Gujarat''s larger paper mills. Kraft paper specialist. Volume buyer of paper chemicals.', 'New', false, '2026-02-18 21:04:40.279708', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (125, 'N.R. Agarwal Industries Limited', 'paper_pulp', 'Gujarat', 'Vapi (Valsad)', 'VP Operations', 'VP Operations', '', '', '+91 260 XXX XXXX', 'Industry Directory', '{"Paper Manufacturing","GIDC Vapi","Large Scale"}', 'Pitch our silicone antifoams for paper production and silicone-based release agents for their coating operations at GIDC Vapi. As a large-scale manufacturer in Gujarat''s industrial corridor, they consume significant volumes of process chemicals monthly. Our antifoams provide superior deaeration compared to fatty acid-based alternatives, improving paper quality and reducing breaks. Offer a volume pricing proposal with a free technical evaluation at their plant.', 'GIDC Vapi, Valsad. Major paper manufacturing operation in Gujarat''s industrial corridor.', 'New', false, '2026-02-18 21:04:40.28931', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (127, 'Nepa Mills Limited', 'paper_pulp', 'Madhya Pradesh', 'Nepanagar (Burhanpur)', 'General Manager (Purchase)', 'GM Procurement', '', '', '+91 7325 XXX XXX', 'Government Mill', '{Newsprint,Government,Historic}', 'Pitch our silicone antifoams for their newsprint manufacturing process and wastewater treatment operations at this historic government mill. Government facilities typically use established supplier lists — our competitive pricing and consistent quality can help them meet cost-reduction targets while improving production efficiency. Offer a formal quotation with full technical data sheets and government procurement-compatible documentation.', 'Nepanagar, Burhanpur, MP. Historic government paper mill. Established supplier relationships but open to competitive offerings.', 'New', false, '2026-02-18 21:04:40.296626', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (129, 'Ion Exchange (India) Ltd', 'water_treatment', 'Maharashtra', 'Mumbai (Mahalaxmi)', 'Head of Chemical Procurement', 'VP Procurement', 'https://www.ionexchangeindia.com', 'https://www.linkedin.com/company/ion-exchange-india', '+91 22 2493 XXXX', 'Public Listed', '{"Ion Exchange Resins","Membrane Tech","Market Leader"}', 'Pitch our silicone-based antifoams for their RO membrane cleaning formulations, boiler water treatment chemicals, and cooling tower operations across India. As the market leader, they formulate and supply chemicals to thousands of industrial customers — making them a high-volume channel partner for our antifoam concentrates. Our antifoams offer superior thermal stability for boiler applications and membrane compatibility for RO systems. Propose a bulk supply agreement with technical support for formulation optimization.', 'Ion House, Dr. E. Moses Road, Mahalaxmi. Listed company. Large-scale operations across India. Volume buyer of water treatment chemicals.', 'New', false, '2026-02-18 21:04:40.303601', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (134, 'Pennar Industries Limited', 'water_treatment', 'Telangana', 'Hyderabad (Kondapur)', 'Business Head (Chemicals)', 'Business Head', 'https://www.pennarindia.com', 'https://www.linkedin.com/company/pennar-industries', '+91 40 4021 XXXX', 'Public Listed', '{PENNTREAT,"Boiler Chemicals","Cooling Water"}', 'Pitch our silicone antifoams for incorporation into their PENNTREAT boiler water treatment, cooling water, and RO antiscalant formulations. Their diversified chemical division formulates branded products that require high-quality antifoam concentrates as raw material. Our domestic supply offers significant cost savings vs. imported antifoam grades, improving their formulation margins. Lead with competitive bulk pricing and offer technical support for antifoam integration into their PENNTREAT product line.', 'Kondapur, Hyderabad. Diversified company with chemical division. PENNTREAT is their water treatment chemical brand.', 'New', false, '2026-02-18 21:04:40.324671', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (137, 'Dadia Chemical Industries', 'leather', 'Maharashtra', 'Mumbai (Ghatkopar East)', 'Managing Director', 'Director', 'https://www.dadiachemicals.com', '', '+91 22 2510 XXXX', 'Company Website', '{"Tanning Chemicals","Supplier to Tanneries"}', 'Pitch our silicone softeners and water-repellent finishes as additions to their existing tanning chemical range for distribution to tanneries. As a chemical supplier rather than end-user, they represent a channel partner opportunity — our products complement their existing portfolio without competing. Bundling our silicone finishes with their tanning chemicals creates a one-stop offering for their tannery customers. Propose a distributor agreement with attractive margins and free product training for their sales team.', 'Ghatkopar East, Mumbai. Supplier of tanning chemicals to tanneries. Potential channel partner for selling Resil products to tanneries.', 'New', false, '2026-02-18 21:04:40.336011', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (140, 'Finolex Cables Limited', 'wire_cable', 'Maharashtra', 'Pune (Pimpri)', 'Head of Sourcing (Raw Materials)', 'Sourcing', 'https://www.finolex.com', 'https://www.linkedin.com/company/finolex-cables', '+91 20 2742 XXXX', 'Public Listed', '{"PVC Winding Wire","Power Cables",Pune}', 'Pitch our Ca-Zn stabilizers for PVC wire insulation compounds at their Pimpri, Urse, and Verna (Goa) plants. Finolex''s quality-conscious procurement process values suppliers with consistent quality and regulatory compliance documentation — our stabilizers come with full EU RoHS data. Consolidating stabilizer sourcing from a single domestic supplier reduces their multi-vendor complexity and improves supply chain reliability. Lead with a technical comparison study against their current stabilizer system with free test samples.', 'Pimpri, Pune HQ. Major PVC cable manufacturer. Also has plants in Urse and Goa. Quality-conscious procurement.', 'New', false, '2026-02-18 21:04:40.34709', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (141, 'KEI Industries Limited', 'wire_cable', 'Maharashtra', 'Mumbai', 'Procurement Manager (Chemicals)', 'Procurement', 'https://www.kei-ind.com', 'https://www.linkedin.com/company/kei-industries', '+91 22 XXXX XXXX', 'Public Listed', '{"Power Cables","2000+ Partners","60+ Countries"}', 'Pitch our Ca-Zn stabilizers and PVC processing aids for cable insulation compounding across their pan-India manufacturing operations. With 2000+ channel partners in 60+ countries, they need RoHS-compliant lead-free stabilizer systems to meet global regulatory requirements. Our Ca-Zn systems provide excellent heat stability and weathering resistance critical for power cable longevity. Lead with a competitive pricing proposal and offer a free processing trial at their nearest manufacturing unit.', 'Mumbai presence. Large-scale wire and cable manufacturer. Pan-India operations. Volume buyer of PVC compounds.', 'New', false, '2026-02-18 21:04:40.351195', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (147, 'Lallan Shoes', 'footwear', 'Maharashtra', 'Mumbai', 'Director', 'Director', 'https://lallanshoes.com', '', '+91 22 XXXX XXXX', 'Company Website', '{"Precision Footwear",Mumbai}', 'Pitch our silicone-based mould release agents for their precision footwear moulding operations and Ca-Zn stabilizers for PVC sole compound manufacturing. Precision crafting demands clean mould release without residue transfer to finished shoes — our silicone release agents provide exactly that consistency. Domestic supply means rapid restocking with no import delays during peak production seasons. Lead with free mould release samples and a cost comparison vs. their current release agent.', 'Mumbai-based footwear manufacturer. Precision crafting suggests quality-conscious operations.', 'New', false, '2026-02-18 21:04:40.380515', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (156, 'MR BOND POLYCHEM', 'adhesives_sealants', 'Gujarat', 'Ahmedabad', 'Technical Director', 'Director', 'https://www.epoxybondpolychem.com', '', '+91 79 XXXX XXXX', 'Company Website', '{"Epoxy Resins","PU Resins","21+ Years"}', 'Pitch our epoxy resins and hardeners for their adhesive and flooring formulations, plus TDI/MDI for their PU-based sealant and paint products. With 21+ years in the business, they are established formulators who directly consume epoxy and PU raw materials in significant volumes. Our domestic production eliminates import dependency and provides competitive landed costs vs. international suppliers. Lead with a competitive pricing comparison and offer free formulation support for their product development.', 'Ahmedabad, Gujarat. 21+ years experience. Both manufacturer and formulator of epoxy and PU products. Direct buyer of our raw materials.', 'New', false, '2026-02-18 21:04:40.413775', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (158, 'Anabond Limited', 'adhesives_sealants', 'Maharashtra', 'Mumbai (Regional Office)', 'Regional Manager (West)', 'Sales', 'https://anabond.com', 'https://www.linkedin.com/company/anabond', '+91 22 XXXX XXXX', 'Company Website', '{Anaerobic,Silicone,Epoxy,PU,"Hot Melts"}', 'Pitch our epoxy resins for their structural adhesive formulations and silicone base compounds for their silicone sealant product line. Since 1979, they''ve built a comprehensive adhesive portfolio that requires both epoxy and silicone raw materials — consolidating supply from us offers procurement efficiency and cost savings. Their Mumbai regional office covers the Western India market with significant volume requirements. Offer a dual-product pricing proposal covering both epoxy resins and silicone base materials.', 'Chennai HQ with Mumbai regional office. Large-scale adhesive manufacturer. Dual opportunity for our (epoxy) and Resil (silicone) products.', 'New', false, '2026-02-18 21:04:40.420026', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (160, 'Medmech Healthcare Pvt Ltd', 'medical_devices', 'Gujarat', 'Vadodara', 'Director', 'Director', 'https://www.medmechindia.com', '', '+91 265 XXX XXXX', 'Company Website', '{"Surgical Gloves","Nitrile Gloves","ISO Certified"}', 'Pitch our silicone-based internal lubricants for powder-free glove donning and silicone release agents for their latex and nitrile surgical glove mould release process. Their ISO certification and export quality standards require consistent, documented silicone lubricants that meet global biocompatibility requirements. Our domestic supply offers significant cost advantage over imported medical-grade silicone fluids. Offer a free trial batch with full biocompatibility documentation and a cost comparison vs. their current imported supplier.', 'Vadodara, Gujarat. Surgical glove manufacturer. ISO certified. Uses silicone lubricants in glove manufacturing process. Direct Resil opportunity.', 'New', false, '2026-02-18 21:04:40.425593', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (163, 'Cartel Healthcare Pvt Ltd', 'medical_devices', 'Maharashtra', 'Mumbai', 'Procurement Manager', 'Procurement', 'https://www.cartelhealthcare.com', '', '+91 22 XXXX XXXX', 'Company Website', '{"Surgical Gloves","Bio-safe Syringes","ISO 13485"}', 'Pitch our medical-grade Dimethicone for syringe barrel lubrication and silicone donning agents for their surgical glove manufacturing. Their ISO 13485 and CE certifications require fully traceable, documented medical-grade silicones — our products come with complete batch documentation and biocompatibility data. Multi-product medical device manufacturers benefit from consolidating their silicone supply from a single qualified vendor. Propose a vendor qualification audit with comprehensive product documentation for their quality team.', 'Mumbai, Maharashtra. Multi-product medical device manufacturer. ISO 13485 certified. Uses medical-grade silicone across product range.', 'New', false, '2026-02-18 21:04:40.437048', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (165, 'Sun Pharmaceutical Industries', 'pharma', 'Gujarat', 'Vadodara (Halol)', 'VP Global Procurement', 'VP Procurement', 'https://www.sunpharma.com', 'https://www.linkedin.com/company/sun-pharma', '+91 265 XXX XXXX', 'Public Listed', '{"Global #4 Generics",Specialty,Dermatology}', 'Pitch our US-DMF filed Simethicone for their GI formulations, process antifoams for API reactors, and dermatology-grade Dimethicone for their specialty skin care product lines at the Halol plant. As the world''s 4th largest generics company with US-FDA audited facilities, they need excipient suppliers with complete regulatory documentation for global filings. Our domestic supply with multi-market compliance reduces their sourcing complexity vs. multiple international suppliers. Lead with a comprehensive regulatory package and offer a vendor qualification audit at our facility.', 'Halol plant is one of their largest. Global operations. Massive volume buyer. High quality standards with US-FDA audited facilities.', 'New', false, '2026-02-18 21:04:40.4435', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (168, 'Crystal Crop Protection', 'agriculture', 'Gujarat', 'Ahmedabad', 'VP Manufacturing', 'VP', '', '', '+91 79 XXXX XXXX', 'Industry Directory', '{Insecticides,Fungicides,Herbicides,PGRs}', 'Pitch our silicone-based spray adjuvants to enhance leaf coverage and rain-fastness of their insecticide, fungicide, and herbicide formulations. Better spray coverage means lower active ingredient dosage for the same efficacy — a direct cost saving for their farmer customers and a formulation differentiator. Our spray adjuvants are compatible with their technical manufacturing processes and can be incorporated into existing formulations. Offer free adjuvant samples for efficacy trials on their key crop protection products.', 'Gujarat-based technical agrochemical manufacturer. Focus on technical manufacturing. Good target for spray adjuvant sales.', 'New', false, '2026-02-18 21:04:40.452233', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (171, 'Asian Paints (Hyderabad Depot)', 'paints', 'Telangana', 'Hyderabad', 'Regional Sourcing Manager', 'Sourcing', 'https://www.asianpaints.com', 'https://www.linkedin.com/company/asian-paints', '+91 40 XXXX XXXX', 'Annual Report', '{Decorative,"Regional Depot","Market Leader"}', 'Pitch our silicone defoamers for their water-based decorative paint formulations and epoxy coating resins for their industrial coatings range through their Hyderabad regional sourcing office. Regional sourcing decisions influence national procurement — establishing a relationship here opens access to their broader South India supply requirements. Our defoamers are specifically formulated for water-based paint systems without causing surface defects. Propose a technical presentation to their regional sourcing team with free defoamer samples for paint formulation testing.', 'Hyderabad regional office. Covers South India market. Regional sourcing decisions can influence national procurement.', 'New', false, '2026-02-18 21:04:40.462061', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (176, 'Lapp India', 'wire_cable', 'Maharashtra', 'Bhiwandi (Thane)', 'Warehouse & Distribution Head', 'Operations', 'https://www.lappindia.com', 'https://www.linkedin.com/company/lapp-india', '+91 2522 XXX XXX', 'MNC', '{"Industrial Cables","PVC Insulated",German}', 'Pitch our Ca-Zn stabilizers and PVC compound additives for their industrial and PVC insulated cable range distributed across Maharashtra, MP, Gujarat, and Chhattisgarh. German MNC quality standards require documented, consistent-quality PVC additives — our Ca-Zn systems with full RoHS compliance meet their parent company specifications. Domestic supply from our operations reduces lead times vs. imported additives for their western India distribution hub. Propose a vendor qualification with comprehensive technical documentation and free compounding samples.', 'Bhiwandi warehouse catering to western India. German parent means high quality standards. Growing India operations.', 'New', false, '2026-02-18 21:04:40.476368', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (178, 'True Build Enterprise', 'construction', 'Telangana', 'Hyderabad', 'Director', 'Director', '', '', '+91 40 XXXX XXXX', 'Industry Directory', '{"SBR Latex",Waterproofing,"Tile Grout"}', 'Pitch our epoxy resin systems for their epoxy grout and flooring products, plus silicone sealants for their waterproofing range. Their growing presence in Hyderabad''s booming construction market creates increasing demand for quality epoxy and silicone raw materials. Our domestic supply chain ensures consistent availability as the Telangana construction sector expands. Lead with competitive pricing on epoxy grout-grade resins and offer free formulation samples for their product development.', 'Hyderabad-based construction chemicals company. Manufactures waterproofing and tile-related products. Growing Telangana construction market.', 'New', false, '2026-02-18 21:04:40.481528', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (180, 'Wilshire Pesticides & Fertilizers', 'agriculture', 'Maharashtra', 'Nashik', 'Director', 'Director', '', '', '+91 253 XXX XXXX', 'Industry Directory', '{Pesticides,Fertilizers,"Since 2012"}', 'Pitch our silicone-based spray adjuvants for improving the leaf coverage, penetration, and rain-fastness of their pesticide formulations. As a newer company since 2012, they are likely more open to new vendor relationships and product innovations than legacy agrochemical firms. Our spray adjuvants differentiate their formulations by delivering better field efficacy at lower application rates. Offer free field trial samples and propose a joint efficacy study on their key pesticide products in Nashik''s agricultural region.', 'Nashik, Maharashtra. Growing agrochemical company. Relatively newer company, likely more accessible for new vendor relationships.', 'New', false, '2026-02-18 21:04:40.489832', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (183, 'Durga Bondchem Pvt Ltd', 'water_treatment', 'Madhya Pradesh', 'Indore', 'Technical Director', 'Director', '', '', '+91 731 XXX XXXX', 'Industry Directory', '{"Water Treatment","Construction Chemicals",Indore}', 'Pitch our silicone antifoams for their water treatment chemical formulations and silicone-based water repellents for their construction chemicals division. Their dual business model means two distinct product opportunities from a single vendor relationship, simplifying their procurement process. Our competitive domestic pricing improves their formulation margins in both water treatment and construction product lines. Offer a dual-product evaluation kit with application-specific samples for both their business divisions.', 'Indore, MP. Dual water treatment and construction chemicals business. Two product lines to target with Resil chemicals.', 'New', false, '2026-02-18 21:04:40.498292', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (185, 'Narmada Agrobase Ltd', 'pvc', 'Gujarat', 'Ahmedabad (Changodar)', 'Purchase Manager', 'Procurement', '', '', '+91 79 XXXX XXXX', 'Industry Directory', '{"PVC Pipes","Drip Irrigation",Agriculture}', 'Pitch our Ca-Zn stabilizers with UV absorber packages specifically formulated for outdoor PVC drip irrigation and agricultural pipe applications. Outdoor irrigation pipes face extreme UV exposure and temperature cycling — our stabilizer-UV absorber combination provides the extended service life that farmers demand. Lead-free Ca-Zn systems also meet evolving BIS standards for pipes in contact with irrigation water. Offer a free extrusion trial with accelerated weathering test data to demonstrate superior UV protection.', 'Changodar, Ahmedabad. Agricultural PVC pipe manufacturer. UV resistance is critical for outdoor irrigation pipes.', 'New', false, '2026-02-18 21:04:40.505854', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (186, 'Harmony Additives Pvt Ltd', 'food_processing', 'Gujarat', 'Umargam (Valsad)', 'Director', 'Director', '', '', '+91 260 XXX XXXX', 'Industry Directory', '{"Silicon Defoamer","DF Series",Industrial}', 'Pitch our silicone antifoam concentrates and silicone fluids as primary base raw material for their DF series defoamer products. As a dedicated silicone defoamer manufacturer, they directly consume bulk silicone fluid — consistent viscosity and quality of our base material is critical for their end-product performance. Our competitive domestic pricing eliminates import duty and forex risk, directly improving their production margins. Lead with a quality evaluation batch matched to their DF series specifications and a competitive annual supply pricing proposal.', 'Umargam, Valsad, Gujarat. Silicone defoamer manufacturer. Direct buyer of silicone fluid raw materials. Key Resil supply opportunity.', 'New', false, '2026-02-18 21:04:40.509387', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (188, 'Fenner (India) Ltd (Madras Rubber)', 'rubber_latex', 'Telangana', 'Hyderabad', 'Regional Manager', 'Manager', 'https://www.fennerindia.com', 'https://www.linkedin.com/company/fenner-india', '+91 40 XXXX XXXX', 'Public Listed', '{"Industrial Rubber","Conveyor Belts",V-Belts}', 'Pitch our silicone-based release agents for their conveyor belt and V-belt mould release operations, plus processing aids for their rubber compounding and vulcanization lines. Industrial rubber product manufacturing generates significant mould fouling — our silicone release agents extend mould life and reduce cleaning downtime between production runs. As a publicly listed company with Chennai HQ, their Hyderabad regional operations need local supplier support. Offer a free plant trial with mould-life extension data and processing efficiency comparison.', 'Hyderabad regional office. Chennai-listed. Industrial rubber products. Uses process chemicals in rubber manufacturing.', 'New', false, '2026-02-18 21:04:40.51578', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (190, 'Nagarjuna Agrichem Limited', 'agriculture', 'Telangana', 'Hyderabad', 'VP Operations', 'VP', '', '', '+91 40 XXXX XXXX', 'Industry Directory', '{Agrochemicals,Fertilizers,"South India"}', 'Pitch our silicone-based spray adjuvants as wetting agents and spreaders for their crop protection formulations targeting South India''s diverse cropping systems. Better spray coverage on waxy leaves (rice, sugarcane) and hairy leaves (cotton) improves pesticide efficacy — a key selling point for their farmer customers. Our adjuvants are compatible with most agrochemical formulations and can be tank-mixed or pre-formulated. Offer free field trial samples for their major crop protection products and propose a joint efficacy demonstration in Telangana.', 'Hyderabad HQ. Agrochemical and fertilizer company. Strong in South India market. Good entry point for Telangana region.', 'New', false, '2026-02-18 21:04:40.52156', 'new', 0, NULL, NULL, NULL, NULL, '[]');
