INSERT INTO public.leads VALUES (195, 'AIMCO Pesticides Ltd', 'agriculture', 'Gujarat', 'Vadodara', 'CEO', 'CEO', '', '', '+91 265 XXX XXXX', 'Industry Directory', '{Pesticides,"Since 1989",Vadodara}', 'Pitch our silicone-based spray adjuvants for improving leaf coverage and rain-fastness of their pesticide formulations across Gujarat''s agricultural market. With 35+ years in the business, they have established farmer relationships where improved spray performance translates directly into customer loyalty and repeat sales. Our organosilicone adjuvants reduce surface tension for superior wetting on difficult-to-spray crops. Offer free adjuvant samples with field trial support and propose a co-branded efficacy demonstration for their key dealer network.', 'Vadodara, Gujarat. Established pesticide manufacturer since 1989. CEO is Pradip Dave. Consistent quality buyer.', 'New', false, '2026-02-18 21:04:40.540466', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (196, 'Mapei India (Pune)', 'construction', 'Maharashtra', 'Pune', 'Technical Procurement Lead', 'Procurement', 'https://www.mapei.com/in', 'https://www.linkedin.com/company/mapei', '+91 20 XXXX XXXX', 'MNC', '{"Tile Adhesives",Waterproofing,Italian}', 'Pitch our epoxy resins for their tile adhesive and concrete restoration formulations, plus silicone-based waterproofing additives for their construction sealant range. As an Italian MNC with a quality-first approach to vendor selection, they need raw material suppliers with comprehensive technical documentation and consistent batch quality. Our domestic supply reduces lead times vs. their current imported specialty chemical sources. Propose a formal vendor qualification meeting with their technical procurement team and offer free resin samples for their formulation lab.', 'High-performance solutions provider. Extensive technical support team. Quality-first approach to vendor selection.', 'New', false, '2026-02-18 21:04:40.543224', 'new', 0, NULL, NULL, NULL, NULL, '[{"id": "1771449848210", "type": "call", "content": "Discussed bulk pricing for silicone oils", "timestamp": "2026-02-18T21:24:08.210Z"}, {"id": "1771449681984", "type": "call", "content": "Initial outreach call - discussed product requirements", "timestamp": "2026-02-18T21:21:21.984Z"}]');
INSERT INTO public.leads VALUES (82, 'Galaxy Surfactants', 'pcd_personal_care', 'Maharashtra', 'Navi Mumbai', 'R&D Director', 'Technical', 'https://www.galaxysurfactants.com', 'https://www.linkedin.com/company/galaxy-surfactants-limited', '9867713628', 'Stock Market', '{Surfactants,"FMCG Ingredients"}', 'Pitch our silicone emulsions engineered for compatibility with their surfactant systems, targeting FMCG personal care formulations. As a BSE/NSE-listed ingredient innovator, they value technical collaboration over simple product sales. Propose a joint formulation development project combining their surfactant expertise with our silicone technology.', 'BSE/NSE listed. Innovator in personal care ingredients. Technical collaboration pitch is stronger than just product sales.', 'Target', true, '2026-02-18 21:04:40.126191', 'contacted', 0, NULL, '8976773575', '2026-02-24', 'call', '[]');
INSERT INTO public.leads VALUES (219, 'Havells India Limited', 'wire_cable', 'Rajasthan', 'Jaipur', 'Purchase Manager', 'Procurement', 'https://www.havells.com', 'https://www.linkedin.com/company/havells-india', NULL, 'AI Discovery', '{"PVC insulation","wire manufacturing","ISO 9001","lead-free products"}', 'Pitch Fabrevol''s Ca-Zn stabilizers for PVC wire insulation to Havells India Limited. Being a major manufacturer of electrical wires and cables, they require high-quality, lead-free stabilizers to enhance the safety and durability of their PVC insulated products. Fabrevol''s stabilizers offer superior regulatory compliance with RoHS and environmental standards, along with cost-effective solutions and stable supply. Initiate contact by offering detailed compliance documentation and a sample trial for their wire insulation lines.', 'Havells India Limited is a large-scale manufacturer with a significant production footprint in Rajasthan and nationwide, certified to ISO standards. They have a structured procurement process with a dedicated purchase department focusing on raw material quality and regulatory compliance. The company is known for adopting eco-friendly materials and modern manufacturing technologies.', 'New', false, '2026-02-23 11:59:10.931539', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (220, 'RR Kabel Limited', 'wire_cable', 'Rajasthan', 'Jaipur', 'Director Procurement', 'Director', 'https://www.rrkabel.com', 'https://www.linkedin.com/company/rrkabel', NULL, 'AI Discovery', '{"wire manufacturing","PVC cables","lead-free stabilizers","ISO 9001"}', 'Introduce Fabrevol’s lead-free stabilizer systems to RR Kabel Limited to support their production of eco-friendly PVC insulated cables. Their focus on sustainability and compliance with global standards demands premium stabilizers that ensure product longevity without toxic additives. Fabrevol''s competitive advantage lies in delivering consistent quality at optimized cost with reliable supply chains. Approach RR Kabel with an offer to conduct a joint product performance evaluation to demonstrate technical benefits.', 'RR Kabel Limited operates a large manufacturing facility with ISO 9001 certification and a commitment to environmentally responsible production. Their procurement team emphasizes supplier reliability and product compliance, often engaging in long-term vendor partnerships. They are expanding capacity and seeking innovative materials to meet international market demands.', 'New', false, '2026-02-23 11:59:10.940775', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (221, 'Vishvkarma Wire Industries', 'wire_cable', 'Rajasthan', 'Sikar', 'VP Operations', 'Operations', NULL, NULL, NULL, 'AI Discovery', '{"PVC insulated wires",plasticizers,"wire manufacturing","regional supplier"}', 'Offer Fabrevol’s plasticizers to Vishvkarma Wire Industries to improve flexibility and durability of their PVC insulated wires. As a regional manufacturer focused on quality and cost-efficiency, they can benefit from our advanced plasticizers that enhance product performance while maintaining cost-effectiveness. Fabrevol ensures reliable supply and technical support tailored for mid-sized manufacturers. Start by proposing a technical consultation followed by a trial batch to demonstrate product benefits.', 'Vishvkarma Wire Industries is a medium-sized manufacturer primarily serving regional markets in Rajasthan. While they may not have extensive certifications, their focus is on delivering quality and affordable wire products. Procurement decisions are typically made by senior operations management with an emphasis on supplier trustworthiness.', 'New', false, '2026-02-23 11:59:10.946717', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (222, 'Aakash Wire Industries', 'wire_cable', 'Rajasthan', 'Udaipur', 'Purchase Manager', 'Procurement', NULL, NULL, NULL, 'AI Discovery', '{"wire & cable manufacturing","PVC insulation","Ca-Zn stabilizers",plasticizers}', 'Recommend Fabrevol''s Ca-Zn stabilizers and plasticizers to Aakash Wire Industries to enhance the quality and environmental compliance of their PVC insulated cables. Their production process requires stable and efficient additives to meet growing market expectations for lead-free and flexible wiring solutions. Fabrevol provides a cost-effective, technically superior alternative with assured supply continuity. The initial approach should include sharing product samples and compliance certifications to build confidence.', 'Aakash Wire Industries operates as a small to medium enterprise in Udaipur with a focus on wire manufacturing for local and regional markets. Procurement is managed by the purchase manager who values product reliability and supplier responsiveness. The company is gradually upgrading its product portfolio to meet modern standards.', 'New', false, '2026-02-23 11:59:10.950302', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.leads VALUES (223, 'Shree Ganesh Wire Industries', 'wire_cable', 'Rajasthan', 'Bhiwadi', 'Director Procurement', 'Director', NULL, NULL, NULL, 'AI Discovery', '{"PVC wire insulation","lead-free stabilizers","wire manufacturing","industrial wires"}', 'Promote Fabrevol''s lead-free stabilizer systems to Shree Ganesh Wire Industries to support their production of industrial-grade PVC insulated wires. Given their emphasis on industrial applications, the need for durable, non-toxic stabilizers is critical to comply with environmental and safety regulations. Fabrevol’s products provide cost advantages, technical reliability, and a steady supply. Engage by proposing a pilot project with detailed technical support and cost-benefit analysis.', 'Shree Ganesh Wire Industries is a small manufacturer located in the industrial hub of Bhiwadi, Rajasthan. They focus on industrial wires and cables with a procurement process led by the director. Their purchasing approach involves careful evaluation of quality and cost efficiency, often favoring suppliers who provide technical collaboration.', 'New', false, '2026-02-23 11:59:10.954289', 'new', 0, NULL, NULL, NULL, NULL, '[]');
INSERT INTO public.products VALUES (1, 'N220 Carbon Black', 'N220 carbon black is a high surface area, medium structure carbon black from the KOHLENSTOFF range. It provides good extrudability in compounds along with high tensile strength and wear resistance.', 'Used in tire tread compounds for passenger and truck tires, conveyor belts, and rubber compounds requiring superior wear and tear resistance.', '{"Rubber & Latex",Footwear,"Wire & Cable","PVC & Plastics"}', '{"carbon black",n220,"rubber filler","tire compound","conveyor belt","wear resistance","tensile strength",kohlenstoff,"rubber reinforcement",carbon}', 'pdf', 'TDS_N220_v2.0.pdf', '2026-02-23 12:35:15.557273');
INSERT INTO public.products VALUES (2, 'Aquaphobe WR 22', 'AQUAPHOBE WR 22 is a water-thinnable, solvent-free silane-siloxane emulsion from Resil Chemicals with excellent penetration properties. It provides superior water repellency for mineral substrates and is eco-friendly.', 'Used for hydrophobic impregnation and priming of construction materials including bricks, sandstone, fiber cement boards, aerated concrete, and mineral plasters. Serves as a water-repellent primer for emulsion paints.', '{"Construction Chemicals","Paints & Coatings"}', '{"water repellent",aquaphobe,"silane siloxane",hydrophobic,impregnation,waterproofing,construction,primer,resil,"wr 22"}', 'pdf', 'AQUAPHOBE_WR_22_TDS.pdf', '2026-02-23 12:35:15.557273');
INSERT INTO public.products VALUES (3, 'Resilwet 103', 'RESILWET 103 is a polyether modified trisiloxane adjuvant (3-(Polyoxyethylene)propylheptamethyltrisiloxane) from Resil Chemicals. It is a highly effective non-ionic surfactant used as a spray adjuvant.', 'Used as a spray adjuvant in agricultural applications for improved wetting, spreading and penetration of agrochemical formulations on plant surfaces.', '{"Agriculture & Agrochemicals"}', '{"spray adjuvant",resilwet,trisiloxane,surfactant,wetter,spreader,"agricultural adjuvant",agrochemical,resil,"silicone surfactant"}', 'pdf', 'RESILWET_103_SDS.pdf', '2026-02-23 12:35:15.557273');
INSERT INTO public.products VALUES (4, 'Resifluid-350 Silicone Fluid', 'RESIFLUID-350 is a colorless polydimethylsiloxane (PDMS) fluid from Resil Chemicals with approximately 370 cst viscosity. It offers excellent thermal stability, low surface tension, high compressibility, and good dielectric properties.', 'Used as a release agent, antifoam, hydraulic fluid, surface-active material, lubricant, and as an additive in polishes and chemical specialties.', '{"Rubber & Latex","Personal Care & Cosmetics",Pharmaceuticals,"Paper & Pulp","Food Processing","Medical Devices"}', '{"silicone fluid",resifluid,pdms,polydimethylsiloxane,"release agent",antifoam,lubricant,"silicone oil","350 cst",resil}', 'pdf', 'TDS-RESILFLUID-350.pdf', '2026-02-23 12:35:15.557273');
INSERT INTO public.products VALUES (5, 'DMC Silicone Fluids (Dimethicone)', 'DMC grade silicone fluids are clear, colorless polydimethylsiloxane fluids from Resil Chemicals available in viscosities from 0.65 to 60,000 cst. They are non-greasy, form protective breathable films, and have excellent water repellency.', 'Used for siliconization of glass, metals, plastics, and rubber. Key applications include pharmaceutical and cosmetic formulations (skin care, sun care, oral care), medical device lubrication (syringes, needles), and industrial lubrication.', '{"Personal Care & Cosmetics",Pharmaceuticals,"Medical Devices","Rubber & Latex","PVC & Plastics"}', '{dimethicone,dmc,"silicone fluid",pdms,polydimethylsiloxane,"cosmetic grade","pharmaceutical grade",siliconization,lubricant,resil}', 'pdf', 'DMC_FLUIDS_TDS.pdf', '2026-02-23 12:35:15.557273');
INSERT INTO public.products VALUES (6, 'Fumed Silica', 'Fumed silica (pyrogenic silica) is an ultrafine, high-purity amorphous silicon dioxide produced by flame hydrolysis. It has extremely high surface area, low bulk density, and unique thixotropic properties.', 'Used as a thickening and anti-settling agent in paints, coatings, and adhesives. Also used as a reinforcing filler in silicone rubber, flow aid in powders, and anti-caking agent in various industrial applications.', '{"Paints & Coatings","Adhesives & Sealants","Rubber & Latex",Pharmaceuticals,"Personal Care & Cosmetics","Construction Chemicals"}', '{"fumed silica","pyrogenic silica","silicon dioxide",sio2,thickener,"rheology modifier",anti-settling,"reinforcing filler",aerosil,thixotropic}', 'text', NULL, '2026-02-23 12:35:15.557273');
INSERT INTO public.products VALUES (7, 'Silicone Oil', 'Silicone oil (polydimethylsiloxane/PDMS) is a versatile clear synthetic fluid available in various viscosity grades. It offers excellent thermal stability, chemical inertness, low surface tension, and superior water repellency.', 'Used as a mold release agent in rubber and plastics, as a lubricant in medical devices and industrial equipment, as a base fluid in personal care products, and as a heat transfer medium in various processes.', '{"Rubber & Latex","Medical Devices","Personal Care & Cosmetics",Pharmaceuticals,"PVC & Plastics","Food Processing","Paper & Pulp"}', '{"silicone oil",pdms,polydimethylsiloxane,"silicone fluid","release agent","mold release",lubricant,"heat transfer","dielectric fluid",silicone}', 'text', NULL, '2026-02-23 12:35:15.557273');
INSERT INTO public.products VALUES (8, 'Calcium Carbonate', 'Calcium Carbonate is an inorganic compound with the chemical formula CaCO3. It is a white, odorless powder or crystalline substance that is widely used as a filler and pigment due to its high brightness, chemical stability, and low abrasiveness. It is commonly derived from natural sources like limestone and marble or produced synthetically.', 'Calcium Carbonate is extensively used as a filler and coating pigment in the paper and plastics industries to improve brightness and opacity. It is also used in paints and coatings to enhance durability and whiteness, as well as in construction chemicals for cement and mortar formulations. Additionally, it serves as a dietary calcium supplement in pharmaceuticals and as a pH regulator in water treatment.', '{Pharmaceuticals,"PVC & Plastics","Paints & Coatings","Construction Chemicals","Paper & Pulp","Water Treatment","Food Processing"}', '{"calcium carbonate",caCO3,limestone,chalk,whiting,filler,pigment,"paper coating","plastic filler","construction additive"}', 'text', NULL, '2026-02-23 12:39:09.349832');
